sys_ws_operation.operation_script:
// FuegoServe REST API — SPA-aware file server
// Auth: requires authenticated SN session (snc_internal role)
// Routes:
//   GET  /api/x_fuegofs/service?/path/to/file    → serve file with MIME + cache headers
//   GET  /api/x_fuegofs/service?/path/to/dir/     → directory listing (JSON)
//   GET  /api/x_fuegofs/service?op=health          → health check
//   GET  /api/x_fuegofs/service?op=list&prefix=/   → explicit directory list
//   POST /api/x_fuegofs/service                     → store file (body: {path, content, mimeType})
//   DELETE /api/x_fuegofs/service?/path/to/file     → delete file

(function process(request, response) {
    var fuego = new x_fuegofs.FuegoServe();
    var method = request.method.toUpperCase();
    var pathParam = request.queryParams['path'] || request.queryParams.toString() || '';

    // If query param starts with / it's a file path (legacy compat: ?/path/to/file)
    var queryStr = request.queryString || '';
    if (!pathParam && queryStr && queryStr.charAt(0) === '/') {
        pathParam = queryStr;
    }

    // ── Auth gate ──
    // Require authenticated session — gs.getUserID() returns 'guest' for unauthenticated
    var userId = gs.getUserID();
    if (!userId || userId === 'guest' || userId === 'system') {
        response.setStatus(401);
        response.setContentType('application/json');
        response.setBody({ error: 'Authentication required', status: 401 });
        return;
    }

    // ── Health check ──
    if (request.queryParams.op === 'health') {
        response.setStatus(200);
        response.setContentType('application/json');
        response.setBody(fuego.health());
        return;
    }

    // ── Directory listing ──
    if (request.queryParams.op === 'list' || request.queryParams.prefix !== undefined) {
        var prefix = request.queryParams.prefix || '/';
        var listing = fuego.listDirectory(prefix);
        response.setStatus(200);
        response.setContentType('application/json');
        response.setBody(listing);
        return;
    }

    // ── POST: Store file ──
    if (method === 'POST') {
        var body = request.body;
        var data = {};
        if (body) {
            try {
                data = JSON.parse(body.data);
            } catch (e) {
                response.setStatus(400);
                response.setContentType('application/json');
                response.setBody({ error: 'Invalid JSON body', detail: e.message });
                return;
            }
        }
        if (!data.path) {
            response.setStatus(400);
            response.setContentType('application/json');
            response.setBody({ error: 'Missing required field: path' });
            return;
        }
        var storeResult = fuego.storeFile(data.path, data.content || '', data.mimeType);
        response.setStatus(200);
        response.setContentType('application/json');
        response.setBody(storeResult);
        return;
    }

    // ── POST: Bulk upload ──
    if (method === 'POST' && request.queryParams.op === 'bulk') {
        var bulkBody = request.body;
        var bulkData = {};
        if (bulkBody) {
            try {
                bulkData = JSON.parse(bulkBody.data);
            } catch (e) {
                response.setStatus(400);
                response.setContentType('application/json');
                response.setBody({ error: 'Invalid JSON body' });
                return;
            }
        }
        if (!bulkData.files || !Array.isArray(bulkData.files)) {
            response.setStatus(400);
            response.setContentType('application/json');
            response.setBody({ error: 'Missing files array' });
            return;
        }
        var bulkResult = fuego.bulkUpload(bulkData.files);
        response.setStatus(200);
        response.setContentType('application/json');
        response.setBody(bulkResult);
        return;
    }

    // ── DELETE: Remove file ──
    if (method === 'DELETE') {
        if (!pathParam || pathParam === '/') {
            response.setStatus(400);
            response.setContentType('application/json');
            response.setBody({ error: 'Path required for deletion' });
            return;
        }
        var delResult = fuego.deleteFile(pathParam);
        response.setStatus(200);
        response.setContentType('application/json');
        response.setBody(delResult);
        return;
    }

    // ── GET: Serve file (default) ──
    if (!pathParam || pathParam === '/' || pathParam === '') {
        pathParam = '/index.html';
    }

    var result = fuego.serve(pathParam);

    if (!result.found) {
        response.setStatus(404);
        response.setContentType('application/json');
        response.setBody({ error: 'File not found', path: pathParam });
        return;
    }

    // Set headers
    response.setContentType(result.mimeType);
    response.setHeader('Cache-Control', result.cacheControl);

    // Add ETag based on content hash (simple)
    var etag = gs.hash(result.content + result.mimeType);
    response.setHeader('ETag', '"' + etag + '"');

    // Handle If-None-Match for 304
    var ifNoneMatch = request.getHeader('If-None-Match');
    if (ifNoneMatch && ifNoneMatch.indexOf(etag) !== -1) {
        response.setStatus(304);
        return;
    }

    // For non-text content that might be binary, we still set as string
    // (SN REST stores content as text in the table; true binary would need base64)
    response.setStatus(200);
    response.setBody(result.content);
})(request, response);
